package org.apache.commons.csv;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Method;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVPrinterTest {

    private Appendable out;
    private CSVFormat format;
    private CSVPrinter printer;

    @BeforeEach
    void setUp() {
        out = new StringBuilder();
        format = mock(CSVFormat.class);
        printer = new CSVPrinter(out, format);
    }

    @Test
    void testPrintRecord_withMultipleObjects() throws Exception {
        // Using reflection to invoke private print(Object) method to spy on it
        CSVPrinter spyPrinter = Mockito.spy(printer);

        // Call printRecord with multiple values
        Object[] values = {"value1", 123, null, 45.6};
        spyPrinter.printRecord(values);

        // Verify print called for each value
        for (Object value : values) {
            verify(spyPrinter).print(value);
        }

        // Verify println called once
        verify(spyPrinter).println();
    }

    @Test
    void testPrintRecord_withEmptyValues() throws IOException {
        // Call printRecord with empty array
        printer.printRecord();
        // The out should have a newline only (println)
        // Since out is StringBuilder, check content
        String result = out.toString();
        // println prints line separator so result length > 0
        // We cannot assert exact content without format details but at least no exception thrown
        // So test passes if no exception
    }
}
